# Deobfuscated Code Analysis

## Step-by-step Deobfuscation

The code uses a common obfuscation pattern with a string array (`a0_0x24ea`), a decoder function (`a0_0x2439`) that base64-decodes entries, and a self-executing shuffler function that rotates the array until a checksum matches.

## Deobfuscated Code

```javascript
// Constants
var TAU = 6.283;          // ~2π
var PHI = 1.618;          // Golden ratio
var SQRT1_2 = 0.707;      // ~√(1/2)

// Simulation configuration
var config = {
  gravity: 4000,           // Repulsion strength between nodes
  stiffness: 0.004,        // Spring stiffness (default)
  velocityDamping: 0.92,   // Velocity friction per frame
  centering: 0.0003,       // Force pulling nodes toward center
  particleRate: 40,        // Max number of particles
  particleSpeed: 0.04,     // Particle speed damping
  deltaTime: 0.06          // Smoothing factor for camera
};

// --- NODES (graph vertices) ---
var nodes = [
  { id: "alpha",   label: "Alpha",   r: 26, x: 400, y: 300, vx: 0, vy: 0 },
  { id: "beta",    label: "Beta",    r: 16, x: 500, y: 200, vx: 0, vy: 0 },
  { id: "sigma",   label: "Sigma",   r: 16, x: 300, y: 400, vx: 0, vy: 0 },
  { id: "gamma",   label: "Gamma",   r: 14, x: 250, y: 180, vx: 0, vy: 0 },
  { id: "delta",   label: "Delta",   r: 14, x: 550, y: 380, vx: 0, vy: 0 },
  { id: "epsilon", label: "Epsilon", r: 12, x: 350, y: 150, vx: 0, vy: 0 }
];

// --- EDGES (springs connecting nodes) ---
var edges = [
  { a: "alpha", b: "beta",    rest: 160, k: 0.006 },
  { a: "alpha", b: "sigma",   rest: 160, k: 0.005 },
  { a: "alpha", b: "gamma",   rest: 170, k: 0.004 },
  { a: "alpha", b: "delta",   rest: 170, k: 0.004 },
  { a: "alpha", b: "epsilon", rest: 180, k: 0.003 },
  { a: "beta",  b: "sigma",   rest: 200, k: 0.002 },
  { a: "gamma", b: "delta",   rest: 220, k: 0.002 },
  { a: "beta",  b: "epsilon", rest: 200, k: 0.002 }
];

// Camera state (current & target)
var camera = { x: 400, y: 300, zoom: 1 };
var cameraTarget = { x: 400, y: 300, zoom: 1 };

// Particles array and frame counter
var particles = [];
var frameCount = 0;

// Find a node by ID
function findNode(id) {
  for (var i = 0; i < nodes.length; i++) {
    if (nodes[i].id === id) return nodes[i];
  }
  return null;
}

// PHYSICS: Apply forces to all nodes
function applyForces() {
  // 1) Node-node REPULSION (inverse-square law, like electric charges)
  for (var i = 0; i < nodes.length; i++) {
    for (var j = i + 1; j < nodes.length; j++) {
      var dx = nodes[i].x - nodes[j].x;
      var dy = nodes[i].y - nodes[j].y;
      var dist = Math.sqrt(dx * dx + dy * dy) || 1;
      var force = config.gravity / (dist * dist);
      var fx = (dx / dist) * force;
      var fy = (dy / dist) * force;
      nodes[i].vx += fx;
      nodes[i].vy += fy;
      nodes[j].vx -= fx;
      nodes[j].vy -= fy;
    }
  }

  // 2) Edge SPRING forces (Hooke's law)
  for (var e = 0; e < edges.length; e++) {
    var nodeA = findNode(edges[e].a);
    var nodeB = findNode(edges[e].b);
    if (!nodeA || !nodeB) continue;
    var dx = nodeB.x - nodeA.x;
    var dy = nodeB.y - nodeA.y;
    var dist = Math.sqrt(dx * dx + dy * dy) || 1;
    var displacement = dist - edges[e].rest;
    var force = (edges[e].k || config.stiffness) * displacement;
    nodeA.vx += (dx / dist) * force;
    nodeA.vy += (dy / dist) * force;
    nodeB.vx -= (dx / dist) * force;
    nodeB.vy -= (dy / dist) * force;
  }

  // 3) INTEGRATE: damping, centering force, position update
  for (var n = 0; n < nodes.length; n++) {
    nodes[n].vx *= config.velocityDamping;          // friction
    nodes[n].vy *= config.velocityDamping;
    nodes[n].vx += (400 - nodes[n].x) * config.centering; // pull toward center (400,300)
    nodes[n].vy += (300 - nodes[n].y) * config.centering;
    nodes[n].x += nodes[n].vx;                      // update position
    nodes[n].y += nodes[n].vy;
  }
}

// SPAWN a decorative particle from a random node
function spawnParticle() {
  if (particles.length >= config.particleRate) return;
  var source = nodes[Math.floor(Math.random() * nodes.length)];
  var angle = Math.random() * TAU;
  var speed = 0.3 + Math.random() * SQRT1_2;
  particles.push({
    x: source.x,
    y: source.y,
    vx: Math.cos(angle) * speed,
    vy: Math.sin(angle) * speed,
    age: 0,
    maxAge: 800 + Math.random() * 1200,
    size: 0.8 + Math.random() * PHI * SQRT1_2
  });
}

// UPDATE particles (move, age, remove dead ones)
function updateParticles() {
  for (var i = particles.length - 1; i >= 0; i--) {
    var p = particles[i];
    p.vx *= 1 - config.particleSpeed * 0.125;  // slow down
    p.vy *= 1 - config.particleSpeed * 0.125;
    p.x += p.vx;
    p.y += p.vy;
    p.age++;
    if (p.age > p.maxAge) particles.splice(i, 1);  // remove expired
  }
}

// SMOOTH camera toward target
function updateCamera() {
  camera.x += (cameraTarget.x - camera.x) * config.deltaTime;
  camera.y += (cameraTarget.y - camera.y) * config.deltaTime;
  camera.zoom += (cameraTarget.zoom - camera.zoom) * config.deltaTime;
}

// MAIN LOOP
function tick() {
  applyForces();
  updateParticles();
  updateCamera();
  if (frameCount % 3 === 0) spawnParticle();  // spawn every 3rd frame
  frameCount++;
}

setInterval(tick, 16);  // ~60fps
```

## What It Does

This is a **force-directed graph layout simulation** — the physics engine behind a node-and-edge visualization (like a network diagram). Specifically:

| Component | Purpose |
|---|---|
| **Nodes** | 6 named entities (Alpha, Beta, Gamma, Delta, Sigma, Epsilon) with positions and velocities |
| **Repulsion** | Nodes push each other apart (inverse-square gravity) to prevent overlap |
| **Springs** | Edges act as springs pulling connected nodes toward a rest distance (Hooke's law) |
| **Centering** | A gentle force pulls everything toward (400, 300) so the graph doesn't drift away |
| **Damping** | Velocity is reduced each frame (0.92×) to prevent infinite oscillation |
| **Particles** | Decorative particles spawn from random nodes and drift outward, fading with age — purely cosmetic |
| **Camera** | Smoothly interpolates toward a target position/zoom (for panning/zooming the view) |

> **In short**: It's the **simulation/physics backend** for an animated, interactive force-directed graph with decorative floating particles. It runs at ~60fps but contains **no rendering code** — it only updates positions. A separate (missing) renderer would draw this to a canvas.
